async function fetchUsers() {
  try {
    const response = await fetch('https://api.example.com/users?page=1&limit=10');
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    const data = await response.json();

    // Filter active users where age > 18 && verified === true
    const activeUsers = data.users.filter(user => user.active && user.age > 18);

    console.log(`Found ${activeUsers.length} active users`);
    return activeUsers;
  } catch (error) {
    console.error('Failed to fetch users:', error.message);
    return [];
  }
}

// Special characters that would break XML without CDATA: < > & " '
// Example: if (x < 10 && y > 20) { return x & y; }

import xml.etree.ElementTree as ET
def parse_catalog(xml_path): """Parse a book catalog XML file and extract book data.""" tree = ET.parse(xml_path) root = tree.getroot()
books = [] for book in root.findall('.//book'): title = book.find('title').text author = book.find('author').text price_elem = book.find('price') price = float(price_elem.text) currency = price_elem.get('currency', 'USD')
# Check if price < 50 && currency == 'USD' if price < 50 and currency == 'USD': books.append({ 'title': title, 'author': author, 'price': f'{currency} {price:.2f}' })
return books
if __name__ == '__main__': results = parse_catalog('catalog.xml') for book in results: print(f" {book['title']} by {book['author']} — {book['price']}")
